import "server-only";

import { neon } from "@neondatabase/serverless";

export function createNeonSql() {
  if (!process.env.DATABASE_URL) {
    throw new Error("DATABASE_URL is required for Neon Postgres");
  }

  return neon(process.env.DATABASE_URL);
}

export const neonBranchingChecklist = [
  "Use preview branches for pull requests",
  "Run migrations before promoting a branch",
  "Keep pooled and direct connection strings separate when needed",
] as const;

const checks = [
  "Install vendor package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function NeonPostgresPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Neon Postgres</h1>
        <p className="text-muted-foreground">Serverless Postgres wiring with branch-aware development guidance.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
